export const serviceFamilies = site.families;
export const allChildren = serviceFamilies.flatMap((family) => family.children.map((child) => ({ ...child, parentSlug: family.slug, parentName: family.name })));
export const corePages = [
  { slug: '', title: 'Home' },
  { slug: 'about', title: 'About Us' },
  { slug: 'contact', title: 'Contact Us' },
  { slug: 'resources', title: 'Resources' },
  { slug: 'blog', title: 'Blog' }
];
export function makeTitle(pageTitle) { return `${pageTitle} | ${site.title}`; }
export function makeServiceTitle(serviceName) { return `${serviceName} in ${site.city || 'Frederick'}, Maryland | ${site.title}`; }
export function getSiblingChildren(parentSlug, childSlug) {
  const family = serviceFamilies.find((item) => item.slug === parentSlug);
  return family ? family.children.filter((child) => child.slug !== childSlug) : [];
}
